from abc import ABC, abstractmethod
from typing import TypeVar, Generic, List, Optional
from contextlib import contextmanager

T = TypeVar('T')

class Repository(Generic[T], ABC):
    """Abstract base repository implementing Unit of Work pattern."""

    @abstractmethod
    def get(self, id: int) -> Optional[T]:
        """Get entity by ID."""
        pass

    @abstractmethod
    def get_all(self) -> List[T]:
        """Get all entities."""
        pass

    @abstractmethod
    def add(self, entity: T) -> T:
        """Add new entity."""
        pass

    @abstractmethod
    def update(self, entity: T) -> T:
        """Update existing entity."""
        pass

    @abstractmethod
    def delete(self, id: int) -> bool:
        """Delete entity by ID."""
        pass

class UnitOfWork:
    """Manages database transactions across multiple repositories."""

    def __init__(self, session_factory):
        self.session_factory = session_factory
        self._session = None
        self._repositories = {}

    @property
    def session(self):
        if self._session is None:
            self._session = self.session_factory()
        return self._session

    def repository(self, entity_class):
        if entity_class not in self._repositories:
            self._repositories[entity_class] = SqlAlchemyRepository(
                self.session, entity_class
            )
        return self._repositories[entity_class]

    @contextmanager
    def transaction(self):
        try:
            yield self
            self.commit()
        except Exception as e:
            self.rollback()
            raise e
        finally:
            self.close()

    def commit(self):
        self.session.commit()

    def rollback(self):
        self.session.rollback()

    def close(self):
        if self._session:
            self._session.close()
            self._session = None

class SqlAlchemyRepository(Repository[T]):
    """Concrete repository implementation using SQLAlchemy."""

    def __init__(self, session, entity_class):
        self._session = session
        self._entity_class = entity_class

    def get(self, id: int) -> Optional[T]:
        return self._session.query(self._entity_class).get(id)

    def get_all(self) -> List[T]:
        return self._session.query(self._entity_class).all()

    def add(self, entity: T) -> T:
        self._session.add(entity)
        return entity

    def update(self, entity: T) -> T:
        self._session.merge(entity)
        return entity

    def delete(self, id: int) -> bool:
        entity = self.get(id)
        if entity:
            self._session.delete(entity)
            return True
        return False
