from abc import ABC, abstractmethod
from typing import Dict, Type, Callable, Any, Optional
from dataclasses import dataclass
from enum import Enum

# Strategy Interface
class PaymentStrategy(ABC):
    """Abstract payment strategy."""

    @abstractmethod
    def pay(self, amount: float, currency: str) -> Dict[str, Any]:
        """Process payment and return transaction details."""
        pass

    @abstractmethod
    def validate(self, payment_details: Dict) -> bool:
        """Validate payment details before processing."""
        pass

    @property
    @abstractmethod
    def name(self) -> str:
        pass

# Concrete Strategies
class StripePaymentStrategy(PaymentStrategy):
    def __init__(self, api_key: str, webhook_secret: str):
        self._api_key = api_key
        self._webhook_secret = webhook_secret

    @property
    def name(self) -> str:
        return "stripe"

    def validate(self, payment_details: Dict) -> bool:
        required = ['card_number', 'exp_month', 'exp_year', 'cvc']
        return all(field in payment_details for field in required)

    def pay(self, amount: float, currency: str) -> Dict[str, Any]:
        # Stripe API integration
        return {
            'success': True,
            'transaction_id': 'txn_stripe_123',
            'amount': amount,
            'currency': currency,
            'provider': 'stripe'
        }

class PayPalPaymentStrategy(PaymentStrategy):
    def __init__(self, client_id: str, client_secret: str, sandbox: bool = False):
        self._client_id = client_id
        self._client_secret = client_secret
        self._sandbox = sandbox

    @property
    def name(self) -> str:
        return "paypal"

    def validate(self, payment_details: Dict) -> bool:
        return 'email' in payment_details or 'paypal_order_id' in payment_details

    def pay(self, amount: float, currency: str) -> Dict[str, Any]:
        return {
            'success': True,
            'transaction_id': 'txn_paypal_456',
            'amount': amount,
            'currency': currency,
            'provider': 'paypal'
        }

class CryptoPaymentStrategy(PaymentStrategy):
    def __init__(self, network: str = 'ethereum', confirmations: int = 6):
        self._network = network
        self._confirmations = confirmations

    @property
    def name(self) -> str:
        return f"crypto_{self._network}"

    def validate(self, payment_details: Dict) -> bool:
        return 'wallet_address' in payment_details and 'tx_hash' in payment_details

    def pay(self, amount: float, currency: str) -> Dict[str, Any]:
        return {
            'success': True,
            'transaction_id': 'txn_crypto_789',
            'amount': amount,
            'currency': currency,
            'provider': self._network,
            'confirmations_required': self._confirmations
        }

# Strategy Factory with DI
class PaymentStrategyFactory:
    """Factory for creating payment strategies with dependency injection."""

    def __init__(self):
        self._strategies: Dict[str, Callable[..., PaymentStrategy]] = {}
        self._configs: Dict[str, Dict] = {}

    def register(
        self, 
        name: str, 
        strategy_class: Type[PaymentStrategy], 
        config: Optional[Dict] = None
    ):
        """Register a strategy with its configuration."""
        self._strategies[name] = strategy_class
        self._configs[name] = config or {}

    def create(self, name: str, **override_config) -> PaymentStrategy:
        """Create strategy instance with merged configuration."""
        if name not in self._strategies:
            raise ValueError(f"Unknown strategy: {name}")

        strategy_class = self._strategies[name]
        config = {**self._configs[name], **override_config}

        return strategy_class(**config)

    def list_strategies(self) -> list:
        return list(self._strategies.keys())

# Context that uses strategies
class PaymentProcessor:
    """Payment processor using strategy pattern."""

    def __init__(self, strategy_factory: PaymentStrategyFactory):
        self._factory = strategy_factory
        self._transaction_history = []

    def process(
        self, 
        strategy_name: str, 
        amount: float, 
        currency: str = 'USD',
        payment_details: Dict = None
    ) -> Dict[str, Any]:
        """Process payment using selected strategy."""

        strategy = self._factory.create(strategy_name)

        # Validate
        if payment_details and not strategy.validate(payment_details):
            return {
                'success': False,
                'error': 'Invalid payment details'
            }

        # Process
        try:
            result = strategy.pay(amount, currency)
            self._transaction_history.append(result)
            return result
        except Exception as e:
            return {
                'success': False,
                'error': str(e)
            }

    def get_history(self) -> list:
        return self._transaction_history.copy()

# Usage Example
def configure_payment_processor() -> PaymentProcessor:
    factory = PaymentStrategyFactory()

    # Register strategies with configs
    factory.register(
        'stripe',
        StripePaymentStrategy,
        {'api_key': 'sk_test_...', 'webhook_secret': 'whsec_...'}
    )

    factory.register(
        'paypal',
        PayPalPaymentStrategy,
        {'client_id': '...', 'client_secret': '...', 'sandbox': True}
    )

    factory.register(
        'crypto',
        CryptoPaymentStrategy,
        {'network': 'ethereum', 'confirmations': 6}
    )

    return PaymentProcessor(factory)
